import socket
import threading
import json
import random
import math

class BattleRoyaleServer:
    def __init__(self, host='localhost', port=12345):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.bind((host, port))
        self.server_socket.listen()
        self.clients = []
        self.players = {}
        self.running = True

    def start(self):
        threading.Thread(target=self.accept_clients).start()

    def accept_clients(self):
        while self.running:
            client_socket, addr = self.server_socket.accept()
            self.clients.append(client_socket)
            threading.Thread(target=self.handle_client, args=(client_socket,)).start()

    def handle_client(self, client_socket):
        player_id = random.randint(1000, 9999)
        self.players[player_id] = {'x': random.random() * 100, 'y': random.random() * 100}
        try:
            while self.running:
                data = client_socket.recv(1024).decode()
                if not data:
                    break
                self.update_player_position(player_id, json.loads(data))
                self.send_game_state()
        finally:
            del self.players[player_id]
            self.clients.remove(client_socket)
            client_socket.close()

    def update_player_position(self, player_id, position):
        self.players[player_id]['x'] = position['x']
        self.players[player_id]['y'] = position['y']

    def send_game_state(self):
        game_state = {'players': self.players}
        for client in self.clients:
            try:
                client.sendall(json.dumps(game_state).encode())
            except:
                self.clients.remove(client)
                client.close()

    def stop(self):
        self.running = False
        for client in self.clients:
            client.close()
        self.server_socket.close()

